108	#[tokio::main]
109	async fn main() {
110	    tracing_subscriber::fmt()
111	        .with_env_filter(
112	            EnvFilter::from_default_env().add_directive("atn=info".parse().unwrap()),
113	        )
114	        .init();
115	
116	    tracing::info!("All Together Now — PGM server starting");
117	
118	    let config_path = std::env::args()
119	        .nth(1)
120	        .unwrap_or_else(|| DEFAULT_CONFIG_PATH.to_string());
121	    let config_path = PathBuf::from(&config_path);
122	
123	    let base_dir = config_path
124	        .parent()
125	        .unwrap_or_else(|| std::path::Path::new("."))
126	        .to_path_buf();
127	
128	    let project_config = load_project_config(&config_path).unwrap_or_else(|e| {
129	        tracing::error!("Failed to load {}: {e}", config_path.display());
130	        tracing::info!("Starting with no agents — create agents.toml to configure");
131	        atn_core::config::ProjectConfig {
132	            project: Default::default(),
133	            agents: vec![],
134	        }
135	    });
136	
137	    let log_dir = project_config
138	        .project
139	        .log_dir
140	        .map(|d| base_dir.join(d));
141	
142	    let mut manager = SessionManager::new(log_dir);
143	
144	    // Spawn all configured agents.
145	    for entry in &project_config.agents {
146	        let config = entry.to_agent_config(&base_dir);
147	        match manager.spawn_agent(config).await {
148	            Ok(id) => tracing::info!("Spawned agent: {id} ({})", entry.name),
149	            Err(e) => tracing::error!("Failed to spawn agent '{}': {e}", entry.id),
150	        }
151	    }
152	
153	    let agent_ids: Vec<String> = manager.agent_ids().iter().map(|id| id.0.clone()).collect();
154	
155	    // Build repo_path map for saga lookups.
156	    let agent_repo_paths: HashMap<String, PathBuf> = project_config
157	        .agents
158	        .iter()
159	        .map(|entry| {
160	            let config = entry.to_agent_config(&base_dir);
161	            (entry.id.clone(), config.repo_path)
162	        })
163	        .collect();
164	    let agent_repo_paths = Arc::new(agent_repo_paths);
165	
166	    tracing::info!(
167	        "{} agent(s) running",
168	        manager.len()
169	    );
170	
171	    // Initialize wiki storage and seed coordination pages.
172	    let wiki_dir = base_dir.join(".atn").join("wiki");
173	    let wiki = Arc::new(FileWikiStorage::new(&wiki_dir));
174	    let now = wiki_common::time::now();
175	    atn_wiki::coordination::seed_coordination_pages(wiki.as_ref(), now).await;
176	    tracing::info!("Wiki storage initialized at {}", wiki_dir.display());
177	
178	    // Initialize event log and message router.
179	    let event_log: router::EventLog = Arc::new(Mutex::new(Vec::new()));
180	    router::ensure_outbox_dirs(&base_dir, &agent_ids).await;
181	    let manager = Arc::new(Mutex::new(manager));
182	
183	    let _router_handle = router::spawn_message_router(
184	        base_dir,
185	        manager.clone(),
186	        wiki.clone(),
187	        event_log.clone(),
188	        std::time::Duration::from_secs(2),
189	    );
190	    tracing::info!("Message router started (polling every 2s)");
191	
192	    let state = SharedState {
193	        manager,
194	        wiki,
195	        event_log,
196	        agent_repo_paths,
197	    };
198	
199	    let app = Router::new()
200	        .route("/", get(index_handler))
201	        .route("/api/agents", get(list_agents))
202	        .route("/api/agents/{id}/sse", get(agent_sse))
203	        .route("/api/agents/{id}/input", post(agent_input))
204	        .route("/api/agents/{id}/ctrl-c", post(agent_ctrl_c))
205	        .route("/api/agents/{id}/state", get(agent_state))
206	        .route("/api/saga", get(get_project_saga))
207	        .route("/api/saga/distill", post(saga_distill))
208	        .route("/api/agents/{id}/saga", get(get_agent_saga))
209	        .route("/api/events", get(list_events).post(submit_event))
210	        .route("/api/wiki", get(wiki_list_pages))
211	        .route(
212	            "/api/wiki/{*title}",
213	            get(wiki_get_page)
214	                .put(wiki_put_page)
215	                .patch(wiki_patch_page)
216	                .delete(wiki_delete_page),
217	        )
218	        .layer(CorsLayer::permissive())
219	        .with_state(state);
220	
221	    let addr = "0.0.0.0:7500";
222	    tracing::info!("Listening on http://{addr}");
223	    let listener = tokio::net::TcpListener::bind(addr).await.unwrap();
224	    axum::serve(listener, app).await.unwrap();
225	}
