231	/// Returns full agent info with state for all agents.
232	async fn list_agents(State(state): State<AppState>) -> Json<Vec<AgentInfo>> {
233	    let pending: Vec<_> = {
234	        let mgr = state.manager.lock().await;
235	        mgr.agent_ids()
236	            .iter()
237	            .filter_map(|id| {
238	                mgr.get_session(id).ok().map(|session| {
239	                    (
240	                        id.0.clone(),
241	                        session.name().to_string(),
242	                        session.role().to_string(),
243	                        session.state(),
244	                    )
245	                })
246	            })
247	            .collect()
248	    };
249	    let mut agents = Vec::with_capacity(pending.len());
250	    for (id, name, role, state_lock) in pending {
251	        let s = state_lock.read().await;
252	        agents.push(AgentInfo {
253	            id,
254	            name,
255	            role,
256	            state: s.clone(),
257	        });
258	    }
259	    Json(agents)
260	}
