262	/// Returns current state for a single agent.
263	async fn agent_state(
264	    Path(id): Path<String>,
265	    State(state): State<AppState>,
266	) -> Result<Json<AgentInfo>, StatusCode> {
267	    let agent_id = AgentId(id);
268	    let (name, role, state_lock) = {
269	        let mgr = state.manager.lock().await;
270	        let session = mgr
271	            .get_session(&agent_id)
272	            .map_err(|_| StatusCode::NOT_FOUND)?;
273	        (
274	            session.name().to_string(),
275	            session.role().to_string(),
276	            session.state(),
277	        )
278	    };
279	    let s = state_lock.read().await;
280	    Ok(Json(AgentInfo {
281	        id: agent_id.0,
282	        name,
283	        role,
284	        state: s.clone(),
285	    }))
286	}
287	
288	async fn agent_sse(
289	    Path(id): Path<String>,
290	    State(state): State<AppState>,
291	) -> Result<Sse<impl futures_core::Stream<Item = Result<Event, Infallible>>>, StatusCode> {
292	    let agent_id = AgentId(id);
293	    let mgr = state.manager.lock().await;
294	    let session = mgr
295	        .get_session(&agent_id)
296	        .map_err(|_| StatusCode::NOT_FOUND)?;
297	    let rx = session.output_receiver();
298	    drop(mgr);
299	
300	    let stream =
301	        tokio_stream::wrappers::BroadcastStream::new(rx).filter_map(|result| match result {
302	            Ok(OutputSignal::Bytes(bytes)) => {
303	                let b64 = base64::engine::general_purpose::STANDARD.encode(&bytes);
304	                Some(Ok(Event::default().data(b64)))
305	            }
306	            _ => None,
307	        });
308	
309	    Ok(Sse::new(stream).keep_alive(KeepAlive::default()))
310	}
311	
312	async fn agent_input(
313	    Path(id): Path<String>,
314	    State(state): State<AppState>,
315	    Json(payload): Json<InputPayload>,
316	) -> Result<StatusCode, StatusCode> {
317	    let agent_id = AgentId(id);
318	    let tx = {
319	        let mgr = state.manager.lock().await;
320	        let session = mgr
321	            .get_session(&agent_id)
322	            .map_err(|_| StatusCode::NOT_FOUND)?;
323	        session.input_sender()
324	    };
325	    tx.send(InputEvent::HumanText {
326	        text: payload.text,
327	    })
328	    .await
329	    .map_err(|_| StatusCode::INTERNAL_SERVER_ERROR)?;
330	    Ok(StatusCode::OK)
331	}
