333	async fn agent_ctrl_c(
334	    Path(id): Path<String>,
335	    State(state): State<AppState>,
336	) -> Result<StatusCode, StatusCode> {
337	    let agent_id = AgentId(id);
338	    let tx = {
339	        let mgr = state.manager.lock().await;
340	        let session = mgr
341	            .get_session(&agent_id)
342	            .map_err(|_| StatusCode::NOT_FOUND)?;
343	        session.input_sender()
344	    };
345	    tx.send(InputEvent::RawBytes {
346	        bytes: vec![0x03],
347	    })
348	    .await
349	    .map_err(|_| StatusCode::INTERNAL_SERVER_ERROR)?;
350	    Ok(StatusCode::OK)
351	}
