353	// ── Saga / Agentrail handlers ─────────────────────────────────────────
354	
355	/// Build a SagaResponse from a repo path (blocking I/O in spawn_blocking).
356	async fn saga_for_path(repo_path: PathBuf) -> SagaResponse {
357	    tokio::task::spawn_blocking(move || {
358	        let saga = atn_trail::reader::load_saga(&repo_path)
359	            .ok()
360	            .flatten();
361	        let steps = atn_trail::reader::list_steps(&repo_path).unwrap_or_default();
362	        let task_type = steps
363	            .iter()
364	            .find(|s| s.status == "in-progress")
365	            .and_then(|s| s.task_type.as_deref())
366	            .unwrap_or("");
367	        let trajectories = if task_type.is_empty() {
368	            vec![]
369	        } else {
370	            atn_trail::reader::load_trajectories(&repo_path, task_type)
371	                .unwrap_or_default()
372	        };
373	        SagaResponse {
374	            saga,
375	            steps,
376	            trajectories,
377	        }
378	    })
379	    .await
380	    .unwrap_or_else(|_| SagaResponse {
381	        saga: None,
382	        steps: vec![],
383	        trajectories: vec![],
384	    })
385	}
386	
387	/// Get saga info for the project (uses cwd).
388	async fn get_project_saga() -> Json<SagaResponse> {
389	    let cwd = std::env::current_dir().unwrap_or_default();
390	    Json(saga_for_path(cwd).await)
391	}
392	
393	/// Get saga info for a specific agent's repo.
394	async fn get_agent_saga(
395	    Path(id): Path<String>,
396	    State(state): State<AppState>,
397	) -> Result<Json<SagaResponse>, StatusCode> {
398	    let repo_path = state
399	        .agent_repo_paths
400	        .get(&id)
401	        .ok_or(StatusCode::NOT_FOUND)?
402	        .clone();
403	    Ok(Json(saga_for_path(repo_path).await))
404	}
