406	/// Trigger skill distillation for a task type.
407	async fn saga_distill(
408	    Json(body): Json<DistillBody>,
409	) -> Result<Json<serde_json::Value>, StatusCode> {
410	    let cwd = std::env::current_dir().unwrap_or_default();
411	    let saga_path = cwd.join(".agentrail");
412	    let (output, code) = atn_trail::cli::agentrail_distill(&saga_path, &body.task_type)
413	        .await
414	        .map_err(|_| StatusCode::INTERNAL_SERVER_ERROR)?;
415	    Ok(Json(serde_json::json!({
416	        "exit_code": code,
417	        "output": output,
418	    })))
419	}
