421	// ── Wiki handlers ──────────────────────────────────────────────────────
422	
423	/// List all wiki page titles.
424	async fn wiki_list_pages(State(state): State<AppState>) -> Json<Vec<String>> {
425	    Json(state.wiki.list_pages().await)
426	}
