428	/// Get a wiki page by title. Returns JSON with ETag header.
429	async fn wiki_get_page(
430	    Path(title): Path<String>,
431	    State(state): State<AppState>,
432	) -> Result<Response, StatusCode> {
433	    let page = state
434	        .wiki
435	        .get_page(&title)
436	        .await
437	        .ok_or(StatusCode::NOT_FOUND)?;
438	
439	    let etag = content_etag(&page.content);
440	    let html = render_wiki_content(&page.content);
441	    let body = WikiPageResponse {
442	        title: page.title,
443	        content: page.content,
444	        html,
445	        created_at: page.created_at,
446	        updated_at: page.updated_at,
447	    };
448	
449	    let mut response = Json(body).into_response();
450	    response
451	        .headers_mut()
452	        .insert("ETag", etag.parse().unwrap());
453	    Ok(response)
454	}
455	
456	/// Create or update a wiki page. Requires If-Match header for existing pages.
457	async fn wiki_put_page(
458	    Path(title): Path<String>,
459	    headers: HeaderMap,
460	    State(state): State<AppState>,
461	    Json(body): Json<WikiPutBody>,
462	) -> Result<Response, Response> {
463	    let existing = state.wiki.get_page(&title).await;
464	    let now = wiki_common::time::now();
465	    let is_update = existing.is_some();
466	    let prev_created_at = existing.as_ref().map(|p| p.created_at);
467	
468	    if let Some(ref page) = existing {
469	        let current_etag = content_etag(&page.content);
470	        let if_match = headers
471	            .get("If-Match")
472	            .and_then(|v| v.to_str().ok())
473	            .map(|s| s.to_string());
474	
475	        match if_match {
476	            None => {
477	                return Err(conflict_response(page, &current_etag));
478	            }
479	            Some(provided) if provided != current_etag => {
480	                return Err(conflict_response(page, &current_etag));
481	            }
482	            _ => {}
483	        }
484	    }
485	
486	    let created_at = prev_created_at.unwrap_or(now);
487	    let page = WikiPage {
488	        title: title.clone(),
489	        content: body.content.clone(),
490	        created_at,
491	        updated_at: now,
492	    };
493	    state.wiki.save_page(page).await;
494	
495	    let etag = content_etag(&body.content);
496	    let html = render_wiki_content(&body.content);
497	    let resp = WikiPageResponse {
498	        title,
499	        content: body.content,
500	        html,
501	        created_at,
502	        updated_at: now,
503	    };
504	
505	    let mut response = Json(resp).into_response();
506	    response
507	        .headers_mut()
508	        .insert("ETag", etag.parse().unwrap());
509	    *response.status_mut() = if is_update {
510	        StatusCode::OK
511	    } else {
512	        StatusCode::CREATED
513	    };
514	    Ok(response)
515	}
516	
517	/// Patch a wiki page using structured operations. Requires If-Match or etag in body.
518	async fn wiki_patch_page(
519	    Path(title): Path<String>,
520	    State(state): State<AppState>,
521	    Json(patch): Json<PatchRequest>,
522	) -> Result<Response, Response> {
523	    let page = state
524	        .wiki
525	        .get_page(&title)
526	        .await
527	        .ok_or_else(|| StatusCode::NOT_FOUND.into_response())?;
528	
529	    let current_etag = content_etag(&page.content);
530	    if patch.etag != current_etag {
531	        return Err(conflict_response(&page, &current_etag));
532	    }
533	
534	    let new_content = apply_ops(&page.content, &patch.ops).map_err(|e| {
535	        (
536	            StatusCode::UNPROCESSABLE_ENTITY,
537	            Json(serde_json::json!({ "error": "patch failed", "op_index": e.op_index, "match_str": e.match_str })),
538	        )
539	            .into_response()
540	    })?;
541	
542	    let now = wiki_common::time::now();
543	    let updated = WikiPage {
544	        title: title.clone(),
545	        content: new_content.clone(),
546	        created_at: page.created_at,
547	        updated_at: now,
548	    };
549	    state.wiki.save_page(updated).await;
550	
551	    let etag = content_etag(&new_content);
552	    let html = render_wiki_content(&new_content);
553	    let resp = WikiPageResponse {
554	        title,
555	        content: new_content,
556	        html,
557	        created_at: page.created_at,
558	        updated_at: now,
559	    };
560	
561	    let mut response = Json(resp).into_response();
562	    response
563	        .headers_mut()
564	        .insert("ETag", etag.parse().unwrap());
565	    Ok(response)
566	}
567	
568	/// Delete a wiki page. Requires If-Match header.
569	async fn wiki_delete_page(
570	    Path(title): Path<String>,
571	    headers: HeaderMap,
572	    State(state): State<AppState>,
573	) -> Result<StatusCode, Response> {
574	    let page = state
575	        .wiki
576	        .get_page(&title)
577	        .await
578	        .ok_or(StatusCode::NOT_FOUND.into_response())?;
579	
580	    let current_etag = content_etag(&page.content);
581	    let if_match = headers
582	        .get("If-Match")
583	        .and_then(|v| v.to_str().ok())
584	        .map(|s| s.to_string());
585	
586	    match if_match {
587	        None => return Err(conflict_response(&page, &current_etag)),
588	        Some(provided) if provided != current_etag => {
589	            return Err(conflict_response(&page, &current_etag));
590	        }
591	        _ => {}
592	    }
593	
594	    state.wiki.delete_page(&title).await;
595	    Ok(StatusCode::NO_CONTENT)
596	}
597	
598	/// Build a 409 Conflict response with current page state.
599	fn conflict_response(page: &WikiPage, current_etag: &str) -> Response {
600	    let body = WikiConflictResponse {
601	        error: "ETag mismatch — page was modified".to_string(),
602	        current_etag: current_etag.to_string(),
603	        page: WikiPageResponse {
604	            title: page.title.clone(),
605	            content: page.content.clone(),
606	            html: render_wiki_content(&page.content),
607	            created_at: page.created_at,
608	            updated_at: page.updated_at,
609	        },
610	    };
611	    let mut resp = Json(body).into_response();
612	    *resp.status_mut() = StatusCode::CONFLICT;
613	    resp.headers_mut()
614	        .insert("ETag", current_etag.parse().unwrap());
615	    resp
616	}
617	
618	// ── Event log handlers ─────────────────────────────────────────────────
619	
620	/// List event log entries. Optional `?since=N` returns entries after index N.
621	async fn list_events(
622	    Query(query): Query<EventLogQuery>,
623	    State(state): State<AppState>,
624	) -> Json<Vec<EventLogEntry>> {
625	    let log = state.event_log.lock().await;
626	    let since = query.since.unwrap_or(0);
627	    Json(log.iter().skip(since).cloned().collect())
628	}
629	
630	/// Submit a push event for routing (e.g., from the UI or an external tool).
631	async fn submit_event(
632	    State(_state): State<AppState>,
633	    Json(body): Json<SubmitEventBody>,
634	) -> StatusCode {
635	    let event = body.event;
636	
637	    // Write the event to the source agent's outbox as a JSON file.
638	    let outbox_dir = PathBuf::from(".atn")
639	        .join("outboxes")
640	        .join(&event.source_agent);
641	    let _ = tokio::fs::create_dir_all(&outbox_dir).await;
642	    let file_path = outbox_dir.join(format!("{}.json", event.id));
643	    if let Ok(json) = serde_json::to_string_pretty(&event) {
644	        let _ = tokio::fs::write(&file_path, json).await;
645	    }
646	
647	    // The background router will pick it up on next poll.
648	    StatusCode::ACCEPTED
649	}
