1	use std::collections::HashSet;
2	use std::path::{Path, PathBuf};
3	use std::sync::Arc;
4	
5	use tokio::sync::Mutex;
6	
7	use atn_core::event::{InputEvent, PushEvent};
8	use atn_core::inbox::{InboxMessage, ATN_DIR_NAME, INBOXES_DIR, OUTBOXES_DIR};
9	use atn_core::router::{route_event, EventLogEntry, RouteDecision};
10	use atn_pty::manager::SessionManager;
11	use atn_wiki::coordination;
12	use atn_wiki::storage::FileWikiStorage;
13	use wiki_common::async_storage::AsyncWikiStorage;
14	
15	/// Shared, append-only event log accessible from REST endpoints.
16	pub type EventLog = Arc<Mutex<Vec<EventLogEntry>>>;
17	
18	/// Create the outbox directories for all configured agents.
19	pub async fn ensure_outbox_dirs(base_dir: &Path, agent_ids: &[String]) {
20	    let outbox_root = base_dir.join(ATN_DIR_NAME).join(OUTBOXES_DIR);
21	    let inbox_root = base_dir.join(ATN_DIR_NAME).join(INBOXES_DIR);
22	    for id in agent_ids {
23	        let _ = tokio::fs::create_dir_all(outbox_root.join(id)).await;
24	        let _ = tokio::fs::create_dir_all(inbox_root.join(id)).await;
25	    }
26	}
27	
28	/// Spawn the background message router task.
29	///
30	/// Polls agent outbox directories every `poll_interval` for new `.json` files.
31	/// Routes each event according to `route_event`, delivers to target PTY or
32	/// escalates to wiki, and appends to the shared event log.
33	pub fn spawn_message_router(
34	    base_dir: PathBuf,
35	    manager: Arc<Mutex<SessionManager>>,
36	    wiki: Arc<FileWikiStorage>,
37	    event_log: EventLog,
38	    poll_interval: std::time::Duration,
39	) -> tokio::task::JoinHandle<()> {
40	    tokio::spawn(async move {
41	        let outbox_root = base_dir.join(ATN_DIR_NAME).join(OUTBOXES_DIR);
42	        let inbox_root = base_dir.join(ATN_DIR_NAME).join(INBOXES_DIR);
43	
44	        loop {
45	            if let Err(e) = poll_once(&outbox_root, &inbox_root, &manager, &wiki, &event_log).await
46	            {
47	                tracing::warn!("Router poll error: {e}");
48	            }
49	            tokio::time::sleep(poll_interval).await;
50	        }
51	    })
52	}
53	
54	async fn poll_once(
55	    outbox_root: &Path,
56	    inbox_root: &Path,
57	    manager: &Arc<Mutex<SessionManager>>,
58	    wiki: &Arc<FileWikiStorage>,
59	    event_log: &EventLog,
60	) -> Result<(), String> {
61	    // List agent outbox directories.
62	    let mut dir_entries = tokio::fs::read_dir(outbox_root)
63	        .await
64	        .map_err(|e| format!("read outbox root: {e}"))?;
65	
66	    while let Some(entry) = dir_entries
67	        .next_entry()
68	        .await
69	        .map_err(|e| format!("read entry: {e}"))?
70	    {
71	        let agent_dir = entry.path();
72	        if !agent_dir.is_dir() {
73	            continue;
74	        }
75	
76	        // Scan for .json files in this agent's outbox.
77	        let mut files = tokio::fs::read_dir(&agent_dir)
78	            .await
79	            .map_err(|e| format!("read agent outbox: {e}"))?;
80	
81	        while let Some(file_entry) = files
82	            .next_entry()
83	            .await
84	            .map_err(|e| format!("read file: {e}"))?
85	        {
86	            let path = file_entry.path();
87	            if path.extension().is_some_and(|ext| ext == "json") {
88	                match process_outbox_file(&path, inbox_root, manager, wiki, event_log).await {
89	                    Ok(()) => {
90	                        // Move processed file to .done to avoid reprocessing.
91	                        let done_path = path.with_extension("json.done");
92	                        let _ = tokio::fs::rename(&path, &done_path).await;
93	                    }
94	                    Err(e) => {
95	                        tracing::warn!("Failed to process {}: {e}", path.display());
96	                    }
97	                }
98	            }
99	        }
100	    }
101	    Ok(())
102	}
103	
104	async fn process_outbox_file(
105	    path: &Path,
106	    inbox_root: &Path,
107	    manager: &Arc<Mutex<SessionManager>>,
108	    wiki: &Arc<FileWikiStorage>,
109	    event_log: &EventLog,
110	) -> Result<(), String> {
111	    let content = tokio::fs::read_to_string(path)
112	        .await
113	        .map_err(|e| format!("read file: {e}"))?;
114	    let event: PushEvent =
115	        serde_json::from_str(&content).map_err(|e| format!("parse PushEvent: {e}"))?;
116	
117	    tracing::info!(
118	        "Router: event {} from {} → {:?}",
119	        event.id,
120	        event.source_agent,
121	        event.target_agent
122	    );
123	
124	    // Get known agent IDs.
125	    let known_agents: HashSet<String> = {
126	        let mgr = manager.lock().await;
127	        mgr.agent_ids().iter().map(|id| id.0.clone()).collect()
128	    };
129	
130	    let decision = route_event(&event, &known_agents);
131	    let now = chrono::Utc::now().to_rfc3339();
132	    let mut delivered = false;
133	
134	    match &decision {
135	        RouteDecision::DeliverToAgent { agent_id } => {
136	            // Write to target agent's inbox.
137	            let inbox_dir = inbox_root.join(agent_id);
138	            let _ = tokio::fs::create_dir_all(&inbox_dir).await;
139	            let inbox_msg = InboxMessage {
140	                event: event.clone(),
141	                delivered: true,
142	                delivered_at: Some(now.clone()),
143	            };
144	            let inbox_path = inbox_dir.join(format!("{}.json", event.id));
145	            let json = serde_json::to_string_pretty(&inbox_msg)
146	                .map_err(|e| format!("serialize inbox: {e}"))?;
147	            tokio::fs::write(&inbox_path, json)
148	                .await
149	                .map_err(|e| format!("write inbox: {e}"))?;
150	
151	            // Poke the target agent's PTY with a notification.
152	            let notification = format!(
153	                "\n[ATN] Message from {}: {} (priority: {:?})\n",
154	                event.source_agent,
155	                event.summary,
156	                event.priority
157	            );
158	            let tx = {
159	                let mgr = manager.lock().await;
160	                mgr.get_session(&atn_core::agent::AgentId(agent_id.clone()))
161	                    .ok()
162	                    .map(|s| s.input_sender())
163	            };
164	            if let Some(tx) = tx {
165	                let _ = tx
166	                    .send(InputEvent::CoordinatorCommand {
167	                        command: format!("# {notification}"),
168	                    })
169	                    .await;
170	            }
171	            delivered = true;
172	            tracing::info!("Router: delivered event {} to agent {}", event.id, agent_id);
173	        }
174	        RouteDecision::Escalate { reason } => {
175	            // Write to wiki Requests page and log for human attention.
176	            let entry = format!(
177	                "**[ESCALATION]** {} → unknown target. Source: {}, Kind: {:?}. Reason: {}",
178	                event.summary, event.source_agent, event.kind, reason,
179	            );
180	            let ts = &now;
181	            let wiki_now = wiki_common::time::now();
182	            coordination::append_log(wiki.as_ref(), &entry, ts, wiki_now).await;
183	            append_to_requests(wiki.as_ref(), &event, reason, wiki_now).await;
184	            tracing::warn!(
185	                "Router: escalated event {} — {}",
186	                event.id,
187	                reason
188	            );
189	        }
190	        RouteDecision::Broadcast => {
191	            // Write to wiki Requests page for visibility.
192	            let entry = format!(
193	                "**[BROADCAST]** {} (from {}, kind: {:?})",
194	                event.summary, event.source_agent, event.kind,
195	            );
196	            let ts = &now;
197	            let wiki_now = wiki_common::time::now();
198	            coordination::append_log(wiki.as_ref(), &entry, ts, wiki_now).await;
199	            append_to_requests(wiki.as_ref(), &event, "no target specified", wiki_now).await;
200	            tracing::info!("Router: broadcast event {} to wiki", event.id);
201	        }
202	    }
203	
204	    // Append to shared event log.
205	    let log_entry = EventLogEntry {
206	        event,
207	        decision: decision.to_string(),
208	        delivered,
209	        logged_at: now,
210	    };
211	    event_log.lock().await.push(log_entry);
212	
213	    Ok(())
214	}
215	
216	async fn append_to_requests(
217	    wiki: &dyn AsyncWikiStorage,
218	    event: &PushEvent,
219	    note: &str,
220	    now: u64,
221	) {
222	    let title = coordination::REQUESTS_PAGE;
223	    let mut page = wiki
224	        .get_page(title)
225	        .await
226	        .unwrap_or_else(|| wiki_common::model::WikiPage::new(title, "# Requests\n\n", now));
227	
228	    page.content.push_str(&format!(
229	        "\n## {} [{}]\n- **From:** {}\n- **Kind:** {:?}\n- **Priority:** {:?}\n- **Note:** {}\n- **ID:** {}\n",
230	        event.summary,
231	        event.timestamp,
232	        event.source_agent,
233	        event.kind,
234	        event.priority,
235	        note,
236	        event.id,
237	    ));
238	    page.updated_at = now;
239	    wiki.save_page(page).await;
240	}
