244	            panel.id = `panel-${agent.id}`;
245	
246	            const sk = stateKey(agent.state);
247	
248	            panel.innerHTML = `
249	                <div class="agent-header">
250	                    <span class="agent-name">${agent.name}</span>
251	                    <span class="agent-role">${agent.role}</span>
252	                    <span id="saga-badge-${agent.id}" style="font-size:11px;color:#a78bfa;"></span>
253	                    <span class="spacer"></span>
254	                    <span class="conn-dot disconnected" id="conn-${agent.id}"></span>
255	                    <span class="state-badge state-${sk}" id="badge-${agent.id}">${stateLabel(agent.state)}</span>
256	                </div>
257	                <div class="agent-terminal" id="term-${agent.id}"></div>
258	                <div class="agent-controls">
259	                    <input type="text" id="input-${agent.id}" placeholder="Command for ${agent.name}...">
260	                    <button class="btn-send" data-agent="${agent.id}">Send</button>
261	                    <button class="btn-ctrl-c" data-agent="${agent.id}">^C</button>
262	                </div>
263	            `;
264	            return panel;
265	        }
266	
267	        function initTerminal(agentId) {
268	            const term = new Terminal({
269	                cursorBlink: true,
270	                fontSize: 13,
271	                fontFamily: "'JetBrains Mono', 'Fira Code', 'Cascadia Code', monospace",
272	                theme: {
273	                    background: '#0d1117',
274	                    foreground: '#c9d1d9',
275	                    cursor: '#e94560',
276	                    selectionBackground: '#264f78',
277	                },
278	            });
279	            const fitAddon = new FitAddon.FitAddon();
280	            term.loadAddon(fitAddon);
281	
282	            const container = document.getElementById(`term-${agentId}`);
283	            term.open(container);
284	            fitAddon.fit();
285	            return { term, fitAddon };
286	        }
287	
288	        function connectSSE(agentId) {
289	            const connDot = document.getElementById(`conn-${agentId}`);
290	            const evtSource = new EventSource(`${API_BASE}/api/agents/${agentId}/sse`);
291	            const agent = agents.get(agentId);
292	
293	            evtSource.onopen = () => {
294	                connDot.className = 'conn-dot connected';
295	            };
296	
297	            evtSource.onmessage = (event) => {
298	                const bytes = Uint8Array.from(atob(event.data), c => c.charCodeAt(0));
299	                agent.term.write(bytes);
300	            };
301	
302	            evtSource.onerror = () => {
303	                connDot.className = 'conn-dot disconnected';
304	                evtSource.close();
305	                setTimeout(() => connectSSE(agentId), 2000);
306	            };
307	
308	            agent.evtSource = evtSource;
309	        }
310	
311	        function setupControls(agentId) {
312	            const input = document.getElementById(`input-${agentId}`);
313	            const panel = document.getElementById(`panel-${agentId}`);
314	            const sendBtn = panel.querySelector('.btn-send');
315	            const ctrlcBtn = panel.querySelector('.btn-ctrl-c');
316	
317	            function doSend() {
318	                const text = input.value;
319	                if (text) {
320	                    fetch(`${API_BASE}/api/agents/${agentId}/input`, {
321	                        method: 'POST',
322	                        headers: { 'Content-Type': 'application/json' },
323	                        body: JSON.stringify({ text }),
324	                    });
325	                    input.value = '';
326	                }
327	                input.focus();
328	            }
329	
330	            sendBtn.addEventListener('click', doSend);
331	            input.addEventListener('keydown', (e) => {
332	                if (e.key === 'Enter') doSend();
333	            });
334	
335	            ctrlcBtn.addEventListener('click', () => {
336	                fetch(`${API_BASE}/api/agents/${agentId}/ctrl-c`, { method: 'POST' });
337	                input.focus();
338	            });
339	        }
340	
341	        // Poll agent states every 2 seconds
342	        async function pollStates() {
343	            try {
344	                const res = await fetch(`${API_BASE}/api/agents`);
345	                if (!res.ok) return;
346	                const list = await res.json();
347	                for (const agent of list) {
348	                    const badge = document.getElementById(`badge-${agent.id}`);
349	                    if (badge) {
350	                        const sk = stateKey(agent.state);
351	                        badge.className = `state-badge state-${sk}`;
352	                        badge.textContent = stateLabel(agent.state);
353	                    }
354	                }
355	            } catch (_) { /* ignore */ }
356	        }
357	
358	        async function pollAgentSagas(agentIds) {
359	            for (const id of agentIds) {
360	                try {
361	                    const res = await fetch(`${API_BASE}/api/agents/${id}/saga`);
362	                    if (!res.ok) continue;
363	                    const data = await res.json();
364	                    const badge = document.getElementById(`saga-badge-${id}`);
365	                    if (badge && data.saga) {
366	                        const current = data.steps.find(s => s.status === 'in-progress');
367	                        badge.textContent = current ? `Step ${current.number}: ${current.slug}` : '';
368	                    }
369	                } catch (_) {}
370	            }
371	        }
372	
373	        async function init() {
374	            const res = await fetch(`${API_BASE}/api/agents`);
375	            const agentList = await res.json();
376	
377	            const dashboard = document.getElementById('dashboard');
378	            const count = agentList.length;
379	            document.getElementById('agent-count').textContent = `${count} agent${count !== 1 ? 's' : ''}`;
380	
381	            // Choose grid columns based on agent count
382	            if (count <= 1) dashboard.className = 'dashboard cols-1';
383	            else if (count <= 2) dashboard.className = 'dashboard cols-2';
384	            else dashboard.className = 'dashboard cols-3';
385	
386	            for (const agent of agentList) {
387	                const panel = createAgentPanel(agent);
388	                dashboard.appendChild(panel);
389	
390	                const { term, fitAddon } = initTerminal(agent.id);
391	                agents.set(agent.id, { term, fitAddon, panel, evtSource: null });
392	
393	                connectSSE(agent.id);
394	                setupControls(agent.id);
395	            }
396	
397	            // Fetch per-agent saga step for badges
398	            pollAgentSagas(agentList.map(a => a.id));
399	
400	            // Handle resize
401	            const fitAll = () => agents.forEach(a => a.fitAddon.fit());
402	            window.addEventListener('resize', fitAll);
403	            new ResizeObserver(fitAll).observe(dashboard);
404	
405	            // Poll states
406	            setInterval(pollStates, 2000);
407	        }
408	
409	        init();
410	
411	        // ── View switching ─────────────────────────────────
412	        function switchView(view) {
413	            document.getElementById('dashboard').style.display = view === 'agents' ? '' : 'none';
414	            document.getElementById('saga-view').style.display = view === 'saga' ? '' : 'none';
415	            document.getElementById('wiki-view').style.display = view === 'wiki' ? '' : 'none';
416	            document.getElementById('events-view').style.display = view === 'events' ? '' : 'none';
417	            for (const t of ['agents', 'saga', 'wiki', 'events']) {
418	                document.getElementById('tab-' + t).className = 'view-tab' + (view === t ? ' active' : '');
419	            }
420	            if (view === 'saga') sagaRefresh();
421	            if (view === 'wiki') wikiLoadPageList();
422	            if (view === 'events') eventsRefresh();
423	        }
424	
425	        // ── Wiki state ─────────────────────────────────────
426	        let wikiCurrentPage = null;
427	        let wikiCurrentEtag = null;
428	        let wikiEditing = false;
429	
430	        async function wikiLoadPageList() {
431	            try {
432	                const res = await fetch(`${API_BASE}/api/wiki`);
433	                const pages = await res.json();
434	                const list = document.getElementById('wiki-page-list');
435	                list.innerHTML = '';
436	                for (const title of pages) {
437	                    const item = document.createElement('div');
438	                    item.className = 'wiki-page-item' + (title === wikiCurrentPage ? ' active' : '');
439	                    item.textContent = title.replace(/__/g, '/');
440	                    item.onclick = () => wikiOpenPage(title);
441	                    list.appendChild(item);
442	                }
443	            } catch (_) {}
444	        }
445	
446	        async function wikiOpenPage(title) {
447	            wikiEditing = false;
448	            try {
449	                const res = await fetch(`${API_BASE}/api/wiki/${encodeURIComponent(title)}`);
450	                if (!res.ok) return;
451	                const data = await res.json();
452	                wikiCurrentPage = title;
453	                wikiCurrentEtag = res.headers.get('ETag');
454	
455	                document.getElementById('wiki-page-title').textContent = data.title;
456	                document.getElementById('wiki-content').innerHTML = data.html;
457	                document.getElementById('wiki-content').style.display = '';
458	                document.getElementById('wiki-edit-area').style.display = 'none';
459	                document.getElementById('wiki-edit-btn').style.display = '';
460	                document.getElementById('wiki-save-btn').style.display = 'none';
461	                document.getElementById('wiki-cancel-btn').style.display = 'none';
462	                document.getElementById('wiki-conflict').style.display = 'none';
463	                document.getElementById('wiki-editor').value = data.content;
464	
465	                // Wire up wiki-link clicks
466	                document.querySelectorAll('#wiki-content a.wiki-link').forEach(a => {
467	                    a.addEventListener('click', (e) => {
468	                        e.preventDefault();
469	                        const target = a.getAttribute('data-wiki-link');
470	                        if (target) wikiOpenPage(target);
471	                    });
472	                });
473	
474	                wikiLoadPageList();
475	            } catch (_) {}
476	        }
477	
478	        function wikiToggleEdit() {
479	            wikiEditing = true;
480	            document.getElementById('wiki-content').style.display = 'none';
481	            document.getElementById('wiki-edit-area').style.display = 'flex';
482	            document.getElementById('wiki-edit-btn').style.display = 'none';
483	            document.getElementById('wiki-save-btn').style.display = '';
484	            document.getElementById('wiki-cancel-btn').style.display = '';
485	        }
486	
487	        function wikiCancelEdit() {
488	            wikiEditing = false;
489	            document.getElementById('wiki-content').style.display = '';
490	            document.getElementById('wiki-edit-area').style.display = 'none';
491	            document.getElementById('wiki-edit-btn').style.display = '';
492	            document.getElementById('wiki-save-btn').style.display = 'none';
493	            document.getElementById('wiki-cancel-btn').style.display = 'none';
494	            document.getElementById('wiki-conflict').style.display = 'none';
495	        }
496	
497	        async function wikiSave() {
498	            if (!wikiCurrentPage) return;
499	            const content = document.getElementById('wiki-editor').value;
500	            const headers = { 'Content-Type': 'application/json' };
501	            if (wikiCurrentEtag) headers['If-Match'] = wikiCurrentEtag;
502	
503	            try {
504	                const res = await fetch(`${API_BASE}/api/wiki/${encodeURIComponent(wikiCurrentPage)}`, {
505	                    method: 'PUT',
506	                    headers,
507	                    body: JSON.stringify({ content }),
508	                });
509	                if (res.status === 409) {
510	                    const data = await res.json();
511	                    document.getElementById('wiki-conflict').textContent =
512	                        `Conflict: page was modified by another user. Current version shown below. Your edits are preserved in the editor.`;
513	                    document.getElementById('wiki-conflict').style.display = '';
514	                    wikiCurrentEtag = data.current_etag;
515	                    return;
516	                }
517	                if (res.ok) {
518	                    wikiCurrentEtag = res.headers.get('ETag');
519	                    wikiOpenPage(wikiCurrentPage);
520	                }
521	            } catch (_) {}
522	        }
523	
524	        async function wikiNewPage() {
525	            const input = document.getElementById('wiki-new-title');
526	            const title = input.value.trim();
527	            if (!title) return;
528	
529	            try {
530	                const res = await fetch(`${API_BASE}/api/wiki/${encodeURIComponent(title)}`, {
531	                    method: 'PUT',
532	                    headers: { 'Content-Type': 'application/json' },
533	                    body: JSON.stringify({ content: `# ${title}\n\n` }),
534	                });
535	                if (res.ok || res.status === 201) {
536	                    input.value = '';
537	                    wikiOpenPage(title);
538	                }
539	            } catch (_) {}
540	        }
541	
542	        // ── Saga ──────────────────────────────────────────────
543	        let sagaCurrentTaskType = null;
544	
545	        async function sagaRefresh() {
546	            try {
547	                const res = await fetch(`${API_BASE}/api/saga`);
548	                if (!res.ok) return;
549	                const data = await res.json();
550	                renderSaga(data);
551	            } catch (_) {}
552	        }
553	
554	        function renderSaga(data) {
555	            const infoDiv = document.getElementById('saga-info');
556	            const stepsDiv = document.getElementById('saga-steps');
557	            const trajDiv = document.getElementById('saga-trajectories');
558	            const trajList = document.getElementById('saga-traj-list');
559	            const distillBtn = document.getElementById('saga-distill-btn');
560	
561	            if (!data.saga) {
562	                infoDiv.innerHTML = '';
563	                stepsDiv.innerHTML = '<div class="saga-none">No .agentrail/ saga found in this project.</div>';
564	                trajDiv.style.display = 'none';
565	                distillBtn.style.display = 'none';
566	                return;
567	            }
568	
569	            const saga = data.saga;
570	            const steps = data.steps;
571	            const completed = steps.filter(s => s.status === 'completed').length;
572	            const total = steps.length;
573	            const current = steps.find(s => s.status === 'in-progress');
574	
575	            infoDiv.innerHTML = `
576	                <div class="saga-stat"><div class="saga-stat-label">Saga</div><div class="saga-stat-value">${saga.name}</div></div>
577	                <div class="saga-stat"><div class="saga-stat-label">Status</div><div class="saga-stat-value">${saga.status}</div></div>
578	                <div class="saga-stat"><div class="saga-stat-label">Progress</div><div class="saga-stat-value">${completed} / ${total}</div></div>
579	                <div class="saga-stat"><div class="saga-stat-label">Current Step</div><div class="saga-stat-value">${current ? current.slug : 'none'}</div></div>
580	            `;
581	
582	            stepsDiv.innerHTML = '';
583	            for (const step of steps) {
584	                const statusCls = 'step-' + step.status.replace(/_/g, '-');
585	                const isCurrent = step.status === 'in-progress';
586	                const card = document.createElement('div');
587	                card.className = `step-card ${statusCls}` + (isCurrent ? ' step-current' : '');
588	                const desc = step.description.length > 120 ? step.description.slice(0, 120) + '...' : step.description;
589	                card.innerHTML = `
590	                    <div class="step-number">${step.number}</div>
591	                    <div class="step-body">
592	                        <div class="step-header">
593	                            <span class="step-slug">${step.slug}</span>
594	                            <span class="step-status">${step.status}</span>
595	                        </div>
596	                        <div class="step-desc">${desc}</div>
597	                        <div class="step-meta">
598	                            ${step.role ? `<span>Role: ${step.role}</span>` : ''}
599	                            ${step.task_type ? `<span>Task: ${step.task_type}</span>` : ''}
600	                            ${step.completed_at ? `<span>Done: ${step.completed_at}</span>` : ''}
601	                        </div>
602	                    </div>
603	                `;
604	                stepsDiv.appendChild(card);
605	            }
606	
607	            // Trajectories
608	            sagaCurrentTaskType = current && current.task_type ? current.task_type : null;
609	            if (data.trajectories.length > 0) {
610	                trajDiv.style.display = '';
611	                trajList.innerHTML = '';
612	                for (const t of data.trajectories) {
613	                    const rewardCls = t.reward > 0 ? 'traj-reward-pos' : (t.reward < 0 ? 'traj-reward-neg' : 'traj-reward-zero');
614	                    const tc = document.createElement('div');
615	                    tc.className = 'traj-card';
616	                    tc.innerHTML = `
617	                        <div class="traj-action">${t.action}</div>
618	                        <div class="traj-meta">
619	                            <span class="${rewardCls}">Reward: ${t.reward > 0 ? '+' : ''}${t.reward}</span>
620	                            &middot; ${t.result} &middot; ${t.timestamp}
621	                        </div>
622	                    `;
623	                    trajList.appendChild(tc);
624	                }
625	                distillBtn.style.display = sagaCurrentTaskType ? '' : 'none';
626	            } else {
627	                trajDiv.style.display = 'none';
628	                distillBtn.style.display = 'none';
629	            }
630	        }
631	
632	        async function sagaDistill() {
633	            if (!sagaCurrentTaskType) return;
634	            const btn = document.getElementById('saga-distill-btn');
635	            btn.textContent = 'Distilling...';
636	            btn.disabled = true;
637	            try {
638	                const res = await fetch(`${API_BASE}/api/saga/distill`, {
639	                    method: 'POST',
640	                    headers: { 'Content-Type': 'application/json' },
641	                    body: JSON.stringify({ task_type: sagaCurrentTaskType }),
642	                });
643	                const data = await res.json();
644	                if (data.exit_code === 0) {
645	                    btn.textContent = 'Distilled!';
646	                } else {
647	                    btn.textContent = 'Distill Failed';
648	                }
649	            } catch (_) {
650	                btn.textContent = 'Error';
651	            }
652	            setTimeout(() => { btn.textContent = 'Distill Skill'; btn.disabled = false; }, 3000);
653	        }
654	
655	        // ── Events log ────────────────────────────────────────
656	        let eventsLastIndex = 0;
657	
658	        const KIND_LABELS = {
659	            feature_request: 'Feature Request',
660	            bug_fix_request: 'Bug Fix',
661	            completion_notice: 'Completed',
662	            blocked_notice: 'Blocked',
663	            needs_info: 'Needs Info',
664	            verification_request: 'Verify',
665	        };
666	
667	        function kindLabel(kind) { return KIND_LABELS[kind] || kind; }
668	
669	        function decisionClass(decision) {
670	            if (decision.startsWith('deliver')) return 'decision-deliver';
671	            if (decision.startsWith('escalate')) return 'decision-escalate';
672	            return 'decision-broadcast';
673	        }
674	
675	        function decisionLabel(decision) {
676	            if (decision.startsWith('deliver:')) return 'Delivered to ' + decision.slice(8);
677	            if (decision.startsWith('escalate:')) return 'Escalated: ' + decision.slice(9);
678	            return 'Broadcast';
679	        }
680	
681	        async function eventsRefresh() {
682	            try {
683	                const res = await fetch(`${API_BASE}/api/events?since=0`);
684	                if (!res.ok) return;
685	                const entries = await res.json();
686	                const list = document.getElementById('events-list');
687	                const escDiv = document.getElementById('events-escalations');
688	                list.innerHTML = '';
689	                escDiv.innerHTML = '';
690	
691	                // Show escalations at the top
692	                const escalations = entries.filter(e => e.decision.startsWith('escalate'));
693	                for (const esc of escalations) {
694	                    const banner = document.createElement('div');
695	                    banner.className = 'escalation-banner';
696	                    banner.innerHTML = `<span class="esc-icon">!</span>
697	                        <span><strong>Human attention needed:</strong> ${esc.event.summary}
698	                        (from ${esc.event.source_agent}, target: ${esc.event.target_agent || 'none'}) &mdash; ${esc.decision.slice(9)}</span>`;
699	                    escDiv.appendChild(banner);
700	                }
701	
702	                // Show all events newest-first
703	                for (let i = entries.length - 1; i >= 0; i--) {
704	                    const entry = entries[i];
705	                    const ev = entry.event;
706	                    const card = document.createElement('div');
707	                    card.className = 'event-card';
708	                    card.innerHTML = `
709	                        <div class="event-header">
710	                            <span class="event-kind kind-${ev.kind}">${kindLabel(ev.kind)}</span>
711	                            <span class="event-decision ${decisionClass(entry.decision)}">${decisionLabel(entry.decision)}</span>
712	                        </div>
713	                        <div class="event-summary">${ev.summary}</div>
714	                        <div class="event-meta">
715	                            <span>From: ${ev.source_agent}</span>
716	                            <span>Target: ${ev.target_agent || '(broadcast)'}</span>
717	                            <span>Priority: ${ev.priority}</span>
718	                            <span>${entry.logged_at}</span>
719	                        </div>`;
720	                    list.appendChild(card);
721	                }
722	                eventsLastIndex = entries.length;
723	            } catch (_) {}
724	        }
725	
726	        // Poll events every 5 seconds for new escalations (shown as badge on tab)
727	        let eventsPollCount = 0;
728	        setInterval(async () => {
729	            try {
730	                const res = await fetch(`${API_BASE}/api/events?since=${eventsLastIndex}`);
731	                if (!res.ok) return;
732	                const entries = await res.json();
733	                if (entries.length > 0) {
734	                    eventsPollCount += entries.length;
735	                    eventsLastIndex += entries.length;
736	                    const tab = document.getElementById('tab-events');
737	                    const hasEscalation = entries.some(e => e.decision.startsWith('escalate'));
738	                    if (hasEscalation) {
739	                        tab.style.borderColor = '#e94560';
740	                        tab.style.color = '#e94560';
741	                    }
742	                    // If events view is active, refresh it
743	                    if (document.getElementById('events-view').style.display !== 'none') {
744	                        eventsRefresh();
745	                    }
746	                }
747	            } catch (_) {}
748	        }, 5000);
749	    </script>
750	</body>
751	</html>
