/// Wait for SIGINT (Ctrl-C) or SIGTERM, then shut down all agents gracefully.
async fn shutdown_signal(state: SharedState) {
    let ctrl_c = async {
        tokio::signal::ctrl_c()
            .await
            .expect("failed to install Ctrl-C handler");
    };

    #[cfg(unix)]
    let terminate = async {
        tokio::signal::unix::signal(tokio::signal::unix::SignalKind::terminate())
            .expect("failed to install SIGTERM handler")
            .recv()
            .await;
    };

    #[cfg(not(unix))]
    let terminate = std::future::pending::<()>();

    tokio::select! {
        () = ctrl_c => tracing::info!("Received Ctrl-C, starting graceful shutdown"),
        () = terminate => tracing::info!("Received SIGTERM, starting graceful shutdown"),
    }

    tracing::info!("Shutting down all agent sessions...");
    let mut mgr = state.manager.lock().await;
    if let Err(e) = mgr.shutdown_all().await {
        tracing::error!("Error during agent shutdown: {e}");
    }
    tracing::info!("All agents shut down. Goodbye.");
}

