input.new_string:
    // Poll events every 5 seconds for new escalations (shown as badge on tab)
    let eventsPollCount = 0;
    setInterval(async () => {
        try {
            const res = await fetch(`${API_BASE}/api/events?since=${eventsLastIndex}`);
            if (!res.ok) return;
            const entries = await res.json();
            if (entries.length > 0) {
                eventsPollCount += entries.length;
                eventsLastIndex += entries.length;
                const tab = document.getElementById('tab-events');
                const hasEscalation = entries.some(e => e.decision.startsWith('escalate'));
                if (hasEscalation) {
                    tab.style.borderColor = '#e94560';
                    tab.style.color = '#e94560';
                    playNotification();
                }
                // If events view is active, refresh it
                if (document.getElementById('events-view').style.display !== 'none') {
                    eventsRefresh();
                }
            }
        } catch (_) {}
    }, 5000);

    // ── Dependency graph ─────────────────────────────────
    const STATE_COLORS = {
        starting: '#9ca3af', running: '#34d399', idle: '#60a5fa',
        awaiting_human_input: '#fbbf24', busy: '#a78bfa', blocked: '#fca5a5',
        completed_task: '#6ee7b7', error: '#f87171', disconnected: '#6b7280',
    };
    const STATE_BG = {
        starting: '#1f2937', running: '#064e3b', idle: '#1e3a5f',
        awaiting_human_input: '#78350f', busy: '#4c1d95', blocked: '#7f1d1d',
        completed_task: '#064e3b', error: '#7f1d1d', disconnected: '#1f2937',
    };

    async function graphRefresh() {
        try {
            const res = await fetch(`${API_BASE}/api/agents/graph`);
            if (!res.ok) return;
            const nodes = await res.json();
            renderGraph(nodes);
        } catch (_) {}
    }

    function renderGraph(nodes) {
        const canvas = document.getElementById('graph-canvas');
        if (nodes.length === 0) {
            canvas.innerHTML = '<div style="color:#666;font-size:14px;">No agents running.</div>';
            return;
        }

        const nodeW = 180, nodeH = 50, padX = 60, padY = 40;
        const cols = Math.min(nodes.length, 4);
        const rows = Math.ceil(nodes.length / cols);
        const svgW = cols * (nodeW + padX) + padX;
        const svgH = rows * (nodeH + padY) + padY;

        // Assign positions
        const positions = {};
        nodes.forEach((n, i) => {
            const col = i % cols;
            const row = Math.floor(i / cols);
            positions[n.id] = {
                x: padX + col * (nodeW + padX),
                y: padY + row * (nodeH + padY),
            };
        });

        let svg = `<svg class="graph-svg" viewBox="0 0 ${svgW} ${svgH}" xmlns="http://www.w3.org/2000/svg">`;
        svg += `<defs><marker id="arrowhead" markerWidth="10" markerHeight="7" refX="10" refY="3.5" orient="auto"><polygon points="0 0, 10 3.5, 0 7" fill="#e94560" /></marker></defs>`;

        // Draw edges (blocked_on -> blocker)
        for (const node of nodes) {
            const to = positions[node.id];
            if (!to) continue;
            for (const dep of node.blocked_on) {
                const from = positions[dep];
                if (!from) continue;
                svg += `<line class="graph-edge" x1="${from.x + nodeW / 2}" y1="${from.y + nodeH}" x2="${to.x + nodeW / 2}" y2="${to.y}" />`;
            }
        }

        // Draw nodes
        for (const node of nodes) {
            const pos = positions[node.id];
            const color = STATE_COLORS[node.state] || '#888';
            const bg = STATE_BG[node.state] || '#16213e';
            svg += `<g class="graph-node">`;
            svg += `<rect x="${pos.x}" y="${pos.y}" width="${nodeW}" height="${nodeH}" fill="${bg}" stroke="${color}" />`;
            svg += `<text x="${pos.x + nodeW / 2}" y="${pos.y + 20}" text-anchor="middle" font-weight="600">${node.name}</text>`;
            svg += `<text x="${pos.x + nodeW / 2}" y="${pos.y + 38}" text-anchor="middle" font-size="11" fill="${color}">${stateLabel({state: node.state})}</text>`;
            svg += `</g>`;
        }

        svg += `</svg>`;
        canvas.innerHTML = svg;
    }

    // ── Notification sounds ──────────────────────────────
    // Use Web Audio API to generate a short attention tone (no external files needed).
    let audioCtx = null;
    let notificationsEnabled = true;
    const prevAgentStates = new Map();

    function playNotification() {
        if (!notificationsEnabled) return;
        try {
            if (!audioCtx) audioCtx = new (window.AudioContext || window.webkitAudioContext)();
            const osc = audioCtx.createOscillator();
            const gain = audioCtx.createGain();
            osc.connect(gain);
            gain.connect(audioCtx.destination);
            osc.type = 'sine';
            osc.frequency.setValueAtTime(880, audioCtx.currentTime);
            osc.frequency.setValueAtTime(660, audioCtx.currentTime + 0.1);
            gain.gain.setValueAtTime(0.3, audioCtx.currentTime);
            gain.gain.exponentialRampToValueAtTime(0.01, audioCtx.currentTime + 0.3);
            osc.start(audioCtx.currentTime);
            osc.stop(audioCtx.currentTime + 0.3);
        } catch (_) {}
    }

    // Check for state changes that need attention during polling.
    const origPollStates = pollStates;
    pollStates = async function() {
        try {
            const res = await fetch(`${API_BASE}/api/agents`);
            if (!res.ok) return;
            const list = await res.json();
            for (const agent of list) {
                const sk = stateKey(agent.state);
                const badge = document.getElementById(`badge-${agent.id}`);
                if (badge) {
                    badge.className = `state-badge state-${sk}`;
                    badge.textContent = stateLabel(agent.state);
                }
                // Play notification on attention-needing state transitions.
                const prev = prevAgentStates.get(agent.id);
                if (prev && prev !== sk && (sk === 'awaiting_human_input' || sk === 'error' || sk === 'blocked')) {
                    playNotification();
                }
                prevAgentStates.set(agent.id, sk);
            }
        } catch (_) {}
    };
</script>

