1	use std::sync::Arc;
2	use std::time::Duration;
3	
4	use tokio::sync::{broadcast, RwLock};
5	use tokio::task::JoinHandle;
6	use tokio::time::Instant;
7	
8	use atn_core::agent::AgentState;
9	use atn_core::event::OutputSignal;
10	
11	const IDLE_TIMEOUT: Duration = Duration::from_secs(5);
12	const PROMPT_MARKER: &[u8] = b"__ATN_READY__>";
13	/// Claude Code displays a question mark or "?" prompt patterns when awaiting input.
14	const QUESTION_MARKERS: &[&[u8]] = &[b"? ", b"(y/n)", b"[Y/n]", b"[y/N]"];
15	
16	/// Spawns a task that monitors PTY output and updates agent state accordingly.
17	///
18	/// State transitions:
19	/// - Bytes received with prompt marker → Idle
20	/// - Bytes received with question markers → AwaitingHumanInput
21	/// - Bytes received (general) → Running
22	/// - No output for IDLE_TIMEOUT → Idle (from Running only)
23	pub fn spawn_state_tracker(
24	    mut rx: broadcast::Receiver<OutputSignal>,
25	    state: Arc<RwLock<AgentState>>,
26	) -> JoinHandle<()> {
27	    tokio::spawn(async move {
28	        let mut last_output = Instant::now();
29	
30	        loop {
31	            tokio::select! {
32	                result = rx.recv() => {
33	                    match result {
34	                        Ok(OutputSignal::Bytes(ref data)) => {
35	                            last_output = Instant::now();
36	                            let new_state = classify_output(data);
37	                            let mut s = state.write().await;
38	                            // Only update if still in a trackable state
39	                            match *s {
40	                                AgentState::Starting
41	                                | AgentState::Running
42	                                | AgentState::Idle
43	                                | AgentState::AwaitingHumanInput => {
44	                                    *s = new_state;
45	                                }
46	                                _ => {}
47	                            }
48	                        }
49	                        Ok(OutputSignal::PromptReady) => {
50	                            let mut s = state.write().await;
51	                            *s = AgentState::Idle;
52	                        }
53	                        Ok(OutputSignal::QuestionDetected { .. }) => {
54	                            let mut s = state.write().await;
55	                            *s = AgentState::AwaitingHumanInput;
56	                        }
57	                        Ok(OutputSignal::IdleDetected) => {
58	                            let mut s = state.write().await;
59	                            if *s == AgentState::Running {
60	                                *s = AgentState::Idle;
61	                            }
62	                        }
63	                        Ok(OutputSignal::PushEvent(_)) => {}
64	                        Err(broadcast::error::RecvError::Lagged(n)) => {
65	                            tracing::debug!("State tracker lagged by {n} messages");
66	                        }
67	                        Err(broadcast::error::RecvError::Closed) => break,
68	                    }
69	                }
70	                _ = tokio::time::sleep_until(last_output + IDLE_TIMEOUT) => {
71	                    let mut s = state.write().await;
72	                    if *s == AgentState::Running {
73	                        *s = AgentState::Idle;
74	                    }
75	                }
76	            }
77	        }
78	    })
79	}
80	
81	/// Classify raw PTY output bytes into an agent state.
82	fn classify_output(data: &[u8]) -> AgentState {
83	    // Check for prompt marker first (most specific)
84	    if contains_bytes(data, PROMPT_MARKER) {
85	        return AgentState::Idle;
86	    }
87	
88	    // Check for question/input-awaiting patterns
89	    for marker in QUESTION_MARKERS {
90	        if contains_bytes(data, marker) {
91	            return AgentState::AwaitingHumanInput;
92	        }
93	    }
94	
95	    AgentState::Running
96	}
97	
98	fn contains_bytes(haystack: &[u8], needle: &[u8]) -> bool {
99	    haystack
100	        .windows(needle.len())
101	        .any(|window| window == needle)
102	}
103	
104	#[cfg(test)]
105	mod tests {
106	    use super::*;
107	
108	    #[test]
109	    fn classify_prompt_as_idle() {
110	        let data = b"some output\r\n__ATN_READY__> ";
111	        assert_eq!(classify_output(data), AgentState::Idle);
112	    }
113	
114	    #[test]
115	    fn classify_question_as_awaiting() {
116	        let data = b"Do you want to proceed? (y/n) ";
117	        assert_eq!(classify_output(data), AgentState::AwaitingHumanInput);
118	    }
119	
120	    #[test]
121	    fn classify_general_output_as_running() {
122	        let data = b"compiling crate foo...";
123	        assert_eq!(classify_output(data), AgentState::Running);
124	    }
125	}
